/// <summary>
/// Extension of the <c>SalesTable</c> form for the ETGSPAIN module.
/// </summary>
[ExtensionOf(FormStr(SalesTable))]
final class SalesTable_ETGSPAIN_Form_Extension
{
}

Method.Source:
/// <summary>
/// Extends the <c>init</c> method to show or hide specific controls based on whether the current company is Spanish.
/// </summary>
/// <remarks>This code is used to show or hide specific characteristics for Spanish companies.</remarks>
public void init()
{
    next init();
    NoYesId currentCompanyIsSpanishCompany  = CurrentCompanyIsSpanishCompany();

    this.design().controlName(formControlStr(SalesTable, ETGSPAINPlate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINPlate_ETGSPAINPlateFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINPlate_ETGSPAINPlateDueDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesTable, ETGSPAINExecution)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINExecution_ETGSPAINPurchExecutionFromDate)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINExecution_ETGSPAINPurchExecutionDueDate)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesTable, ETGSPAINAppliedInventLocation)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesTable, ETGSPAINPorts)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINPorts_ETGSPAINPurchUnloadPortId)).visible(currentCompanyIsSpanishCompany);
    this.design().controlName(formControlStr(SalesTable, ETGSPAINPorts_ETGSPAINPurchLoadPortId)).visible(currentCompanyIsSpanishCompany);

    this.design().controlName(formControlStr(SalesTable, ETGSPAINUnsoldInventTransModifyController)).visible(currentCompanyIsSpanishCompany);        
}
